270→//	-----------------------------------------------------------------------------
271→//	Called when control center gets destroyed.
272→//	This code is common to whether control center is implicitly imbedded in a boss,
273→//	or is an object of its own.
274→//	if objp == NULL that means the boss was the control center and don't set Dead_controlcen_object_num
275→void do_controlcen_destroyed_stuff(object *objp)
276→{
277→	int	i;
278→
279→   if ((Game_mode & GM_MULTI_ROBOTS) && Control_center_destroyed) 
280→    return; // Don't allow resetting if control center and boss on same level
281→
282→	// Must toggle walls whether it is a boss or control center.
283→	for (i=0;i<ControlCenterTriggers.num_links;i++)
284→		wall_toggle(&Segments[ControlCenterTriggers.seg[i]], ControlCenterTriggers.side[i]); 
285→
286→	// And start the countdown stuff.
287→	Control_center_destroyed = 1;
288→
289→	//	If a secret level, delete secret.sgc to indicate that we can't return to our secret level.
290→	if (Current_level_num < 0) 
291→	{
292→		int	rval;
293→#if defined(CHOCOLATE_USE_LOCALIZED_PATHS)
294→		char secretc_full_path[CHOCOLATE_MAX_FILE_PATH_SIZE];
295→		get_full_file_path(secretc_full_path, "secret.sgc", CHOCOLATE_SAVE_DIR);
296→		rval = _unlink(secretc_full_path);
297→#else
298→		rval = _unlink("secret.sgc");
299→#endif
300→		mprintf((0, "Deleting secret.sgc, return value = %i\n", rval));
301→	}
302→
303→	if (CurrentDataVersion == DataVer::DEMO)
304→	{
305→		Total_countdown_time = Base_control_center_explosion_time + Base_control_center_explosion_time * (NDL - Difficulty_level - 1) / 4 - 1;
306→	}
307→	else
308→	{
309→		if (Base_control_center_explosion_time != DEFAULT_CONTROL_CENTER_EXPLOSION_TIME)
310→			Total_countdown_time = Base_control_center_explosion_time + Base_control_center_explosion_time * (NDL - Difficulty_level - 1) / 2;
311→		else
312→			Total_countdown_time = Alan_pavlish_reactor_times[Difficulty_level];
313→	}
314→
315→	Countdown_timer = i2f(Total_countdown_time);
316→
317→	if (!Control_center_present || objp==NULL) {
318→		//Assert(objp == NULL);
319→		return;
320→	}
321→
322→	//Assert(objp != NULL);
323→
324→	Dead_controlcen_object_num = objp-Objects;
325→}
