void cd_ox_spin_object(
    int32_t spin_rx, int32_t spin_ry, int32_t spin_rz,
    int32_t o_rx, int32_t o_ry, int32_t o_rz,
    int32_t o_ux, int32_t o_uy, int32_t o_uz,
